{"content": "     1|<!DOCTYPE html>
     2|<html lang="en">
     3|<head>
     4|<meta charset="UTF-8">
     5|<meta name="viewport" content="width=device-width, initial-scale=1.0">
     6|<title>Awesome Novel Studio — AI Web Novel Creation Harness</title>
     7|<meta property="og:title" content="Awesome Novel Studio — AI Web Novel Creation Harness">
     8|<meta property="og:description" content="18 agents, 10 skills, 16-axis polish. A harness-written novel signed a publishing deal.">
     9|<meta property="og:url" content="https://MJbae.github.io/novel-studio/">
    10|<meta property="og:type" content="website">
    11|<meta name="twitter:card" content="summary_large_image">
    12|<link rel="preconnect" href="https://fonts.googleapis.com">
    13|<link rel="preconnect" href="https://fonts.gstatic.com" crossorigin>
    14|<link rel="stylesheet" href="https://fonts.googleapis.com/css2?family=Inter:wght@400;600;700;800&family=Noto+Sans+KR:wght@400;600;700;800&family=JetBrains+Mono:wght@400;600&family=Playfair+Display:wght@700;900&display=swap">
    15|<style>
    16|*,*::before,*::after{margin:0;padding:0;box-sizing:border-box}
    17|:root{
    18|  --accent:#f59e0b;
    19|  --accent2:#fbbf24;
    20|  --accent-glow:rgba(245,158,11,0.25);
    21|  --green:#10b981;
    22|  --bg:#080a14;
    23|  --surface:#111827;
    24|  --surface2:#0f172a;
    25|  --text:#e2e8f0;
    26|  --text-dim:#94a3b8;
    27|  --border:rgba(255,255,255,0.06);
    28|  --radius:16px;
    29|  font-family:'Inter',-apple-system,BlinkMacSystemFont,'Segoe UI',sans-serif;
    30|}
    31|html.lang-ko{font-family:'Noto Sans KR',-apple-system,sans-serif}
    32|html{scroll-behavior:smooth;font-size:16px}
    33|body{font-family:inherit;background:var(--bg);color:var(--text);line-height:1.7;overflow-x:hidden}
    34|h1,h2,h3{font-weight:700;letter-spacing:-.02em;line-height:1.2}
    35|h2{font-size:clamp(1.8rem,3.5vw,2.8rem);margin-bottom:1rem}
    36|h3{font-size:1.15rem}
    37|p{color:var(--text-dim);max-width:640px}
    38|a{color:var(--accent2);text-decoration:none;transition:color .2s}
    39|a:hover{color:#fcd34d}
    40|.container{max-width:1100px;margin:0 auto;padding:0 2rem;position:relative;z-index:1}
    41|section{padding:6rem 0}
    42|
    43|/* ── Language Toggle ── */
    44|.lang-toggle{position:fixed;top:1.2rem;right:1.5rem;z-index:100;display:flex;gap:2px;background:var(--surface);border:1px solid var(--border);border-radius:10px;padding:3px;backdrop-filter:blur(12px);-webkit-backdrop-filter:blur(12px)}
    45|.lang-btn{padding:.3rem .7rem;border:none;border-radius:7px;font-size:.75rem;font-weight:600;color:var(--text-dim);background:transparent;cursor:pointer;transition:all .2s;font-family:inherit;letter-spacing:.03em}
    46|.lang-btn:hover{color:var(--text)}
    47|.lang-btn.active{background:var(--accent);color:#fff;box-shadow:0 0 12px var(--accent-glow)}
    48|
    49|/* ── Section helpers ── */
    50|.section-tag{display:inline-block;font-size:.7rem;font-weight:700;letter-spacing:.15em;text-transform:uppercase;color:var(--accent);background:rgba(245,158,11,0.1);border:1px solid rgba(245,158,11,0.2);padding:.3rem 1rem;border-radius:100px;margin-bottom:1.2rem}
    51|.section-desc{font-size:1.05rem;color:var(--text-dim);max-width:600px;margin:0 auto;line-height:1.8}
    52|.section-alt{background:var(--surface2)}
    53|.text-center{text-align:center}
    54|
    55|/* ── Hero ── */
    56|.hero{min-height:100vh;display:flex;align-items:center;justify-content:center;text-align:center;position:relative;background:radial-gradient(ellipse at 50% 0%,rgba(245,158,11,0.06) 0%,transparent 60%)}
    57|.hero-inner{max-width:780px}
    58|.badge{display:inline-block;padding:.4rem 1.2rem;border-radius:100px;font-size:.75rem;font-weight:600;letter-spacing:.1em;text-transform:uppercase;background:rgba(245,158,11,0.1);color:var(--accent2);border:1px solid rgba(245,158,11,0.25);margin-bottom:2rem}
    59|.badge-dot{display:inline-block;width:6px;height:6px;border-radius:50%;background:var(--green);margin-right:.5rem;animation:pulse-dot 2s infinite}
    60|@keyframes pulse-dot{0%,100%{opacity:1}50%{opacity:.4}}
    61|.hero h1{font-family:'Playfair Display',serif;font-size:clamp(3rem,7vw,5.5rem);font-weight:900;margin-bottom:1rem}
    62|.hero h1 .accent{background:linear-gradient(135deg,var(--accent2),var(--accent));-webkit-background-clip:text;-webkit-text-fill-color:transparent;background-clip:text}
    63|.hero-sub{font-size:1.15rem;color:var(--text-dim);margin:0 auto 2.5rem;max-width:480px;line-height:1.8}
    64|.hero-sub strong{color:var(--accent2)}
    65|
    66|/* ── Proof box ── */
    67|.proof-box{display:inline-flex;align-items:center;gap:1rem;background:var(--surface);border:1px solid rgba(245,158,11,0.2);border-radius:var(--radius);padding:1rem 1.8rem;margin-bottom:2.5rem;text-align:left}
    68|.proof-icon{font-size:2rem}
    69|.proof-label{font-size:.75rem;color:var(--text-dim);letter-spacing:.03em}
    70|.proof-title{font-size:1rem;font-weight:700;color:var(--accent2)}
    71|.proof-note{font-size:.7rem;color:var(--text-dim);margin-top:.2rem}
    72|
    73|/* ── Metric cards ── */
    74|.metrics-row{display:flex;gap:1.2rem;justify-content:center;flex-wrap:wrap}
    75|.metric-card{background:var(--surface);border:1px solid var(--border);border-radius:var(--radius);padding:1.5rem 2rem;min-width:160px;text-align:center;transition:all .3s}
    76|.metric-card:hover{transform:translateY(-4px);box-shadow:0 16px 48px rgba(245,158,11,0.15);border-color:rgba(245,158,11,0.3)}
    77|.metric-icon{font-size:1.6rem;margin-bottom:.5rem}
    78|.metric-value{font-size:2.2rem;font-weight:800;background:linear-gradient(135deg,var(--accent2),var(--green));-webkit-background-clip:text;-webkit-text-fill-color:transparent;background-clip:text}
    79|.metric-label{font-size:.8rem;color:var(--text-dim);margin-top:.3rem}
    80|
    81|/* ── Problem cards (THE WALL) ── */
    82|.problem-grid{display:grid;grid-template-columns:repeat(auto-fit,minmax(280px,1fr));gap:1.5rem;margin-top:3rem}
    83|.problem-card{background:var(--surface);border:1px solid var(--border);border-top:3px solid var(--accent);border-radius:var(--radius);padding:2rem;transition:all .3s}
    84|.problem-card:hover{transform:translateY(-3px);box-shadow:0 16px 48px rgba(0,0,0,.3)}
    85|.problem-card.card-amber{border-top-color:#f59e0b}
    86|.problem-card.card-blue{border-top-color:#3b82f6}
    87|.problem-card.card-purple{border-top-color:#8b5cf6}
    88|.problem-icon{width:44px;height:44px;border-radius:12px;display:flex;align-items:center;justify-content:center;font-size:1.3rem;margin-bottom:1rem}
    89|.problem-icon.icon-amber{background:rgba(245,158,11,0.1)}
    90|.problem-icon.icon-blue{background:rgba(59,130,246,0.1)}
    91|.problem-icon.icon-purple{background:rgba(139,92,246,0.1)}
    92|.problem-card h3{margin-bottom:.5rem;color:var(--text)}
    93|.problem-card>p{font-size:.88rem;line-height:1.7;margin-bottom:1.2rem}
    94|.solution-box{border:1px solid rgba(245,158,11,0.25);border-radius:12px;padding:1rem 1.2rem;background:rgba(245,158,11,0.03)}
    95|.solution-box.sol-blue{border-color:rgba(59,130,246,0.25);background:rgba(59,130,246,0.03)}
    96|.solution-box.sol-purple{border-color:rgba(139,92,246,0.25);background:rgba(139,92,246,0.03)}
    97|.solution-tag{display:inline-block;font-size:.65rem;font-weight:700;letter-spacing:.08em;padding:.2rem .6rem;border-radius:6px;color:#fff;margin-bottom:.5rem}
    98|.solution-tag.tag-amber{background:#f59e0b}
    99|.solution-tag.tag-blue{background:#3b82f6}
   100|.solution-tag.tag-purple{background:#8b5cf6}
   101|.solution-name{font-size:.9rem;font-weight:700;color:var(--text);margin-bottom:.3rem;font-family:'JetBrains Mono',monospace}
   102|.solution-desc{font-size:.8rem;color:var(--text-dim);line-height:1.6}
   103|
   104|/* ── Pipeline (vertical) ── */
   105|.pipeline-track{display:flex;flex-direction:column;gap:0;margin-top:3rem;position:relative;max-width:600px;margin-left:auto;margin-right:auto}
   106|.pipeline-track::before{content:'';position:absolute;left:28px;top:0;bottom:0;width:2px;background:linear-gradient(to bottom,var(--accent),var(--green),#8b5cf6,#ec4899);opacity:.3}
   107|.pipe-step{display:flex;gap:1.5rem;align-items:flex-start;padding:1.2rem 0;opacity:.4;transform:translateX(-20px);transition:all .5s ease}
   108|.pipe-step.active{opacity:1;transform:translateX(0)}
   109|.pipe-dot{width:56px;min-width:56px;height:56px;border-radius:50%;display:flex;align-items:center;justify-content:center;font-size:1.4rem;background:var(--surface);border:2px solid var(--border);transition:all .4s;position:relative;z-index:1}
   110|.pipe-step.active .pipe-dot{box-shadow:0 0 20px var(--accent-glow)}
   111|.pipe-step.active .pipe-dot.dot-amber{border-color:#f59e0b;background:rgba(245,158,11,0.1)}
   112|.pipe-step.active .pipe-dot.dot-blue{border-color:#3b82f6;background:rgba(59,130,246,0.1)}
   113|.pipe-step.active .pipe-dot.dot-green{border-color:#10b981;background:rgba(16,185,129,0.1)}
   114|.pipe-step.active .pipe-dot.dot-purple{border-color:#8b5cf6;background:rgba(139,92,246,0.1)}
   115|.pipe-step.active .pipe-dot.dot-pink{border-color:#ec4899;background:rgba(236,72,153,0.1)}
   116|.pipe-cmd{font-family:'JetBrains Mono',monospace;font-size:1rem;font-weight:600;margin-bottom:.1rem}
   117|.pipe-cmd.cmd-amber{color:#f59e0b}
   118|.pipe-cmd.cmd-blue{color:#3b82f6}
   119|.pipe-cmd.cmd-green{color:#10b981}
   120|.pipe-cmd.cmd-purple{color:#8b5cf6}
   121|.pipe-cmd.cmd-pink{color:#ec4899}
   122|.pipe-label{font-size:.85rem;font-weight:600;color:var(--text);margin-bottom:.2rem}
   123|.pipe-desc{font-size:.82rem;color:var(--text-dim);line-height:1.5}
   124|
   125|/* ── Agents ── */
   126|.agent-grid{display:grid;grid-template-columns:repeat(2,1fr);gap:1.2rem;margin-top:3rem}
   127|.agent-phase{background:var(--surface);border:1px solid var(--border);border-radius:var(--radius);padding:1.5rem}
   128|.agent-phase-header{display:flex;align-items:center;gap:.6rem;margin-bottom:1rem}
   129|.agent-phase-dot{width:10px;height:10px;border-radius:50%}
   130|.agent-phase-label{font-weight:700;font-size:.95rem}
   131|.agent-phase-count{font-size:.8rem;font-weight:700;margin-left:auto}
   132|.agent-chips{display:flex;flex-wrap:wrap;gap:.5rem}
   133|.agent-chip{display:inline-flex;align-items:center;gap:.4rem;padding:.35rem .7rem;border-radius:100px;border:1px solid var(--border);font-size:.75rem;font-family:'JetBrains Mono',monospace;transition:all .2s;cursor:default}
   134|.agent-chip:hover{transform:scale(1.06);filter:brightness(1.2)}
   135|.chip-blue{border-color:rgba(59,130,246,0.2);background:rgba(59,130,246,0.05);color:#3b82f6}
   136|.chip-green{border-color:rgba(16,185,129,0.2);background:rgba(16,185,129,0.05);color:#10b981}
   137|.chip-purple{border-color:rgba(139,92,246,0.2);background:rgba(139,92,246,0.05);color:#8b5cf6}
   138|.chip-pink{border-color:rgba(236,72,153,0.2);background:rgba(236,72,153,0.05);color:#ec4899}
   139|
   140|/* ── Axes grid ── */
   141|.axes-grid{display:grid;grid-template-columns:repeat(4,1fr);gap:.8rem;margin-top:3rem}
   142|.axis-item{background:var(--surface);border:1px solid var(--border);border-radius:12px;padding:1rem;text-align:center;transition:all .3s;cursor:default}
   143|.axis-item:hover{transform:scale(1.04)}
   144|.axis-id{display:inline-flex;align-items:center;justify-content:center;width:28px;height:28px;border-radius:50%;border:1.5px solid;font-size:.7rem;font-weight:700;margin-bottom:.4rem}
   145|.axis-name{font-size:.8rem;font-weight:700;color:var(--text);margin-bottom:.2rem;font-family:'JetBrains Mono',monospace}
   146|.axis-desc{font-size:.7rem;color:var(--text-dim)}
   147|.ax-red{border-color:rgba(239,68,68,0.3);background:rgba(239,68,68,0.04)}
   148|.ax-red .axis-id{color:#ef4444;border-color:rgba(239,68,68,0.4)}
   149|.ax-amber{border-color:rgba(245,158,11,0.3);background:rgba(245,158,11,0.04)}
   150|.ax-amber .axis-id{color:#f59e0b;border-color:rgba(245,158,11,0.4)}
   151|.ax-purple{border-color:rgba(139,92,246,0.3);background:rgba(139,92,246,0.04)}
   152|.ax-purple .axis-id{color:#8b5cf6;border-color:rgba(139,92,246,0.4)}
   153|.ax-blue{border-color:rgba(59,130,246,0.3);background:rgba(59,130,246,0.04)}
   154|.ax-blue .axis-id{color:#3b82f6;border-color:rgba(59,130,246,0.4)}
   155|.ax-green{border-color:rgba(16,185,129,0.3);background:rgba(16,185,129,0.04)}
   156|.ax-green .axis-id{color:#10b981;border-color:rgba(16,185,129,0.4)}
   157|.ax-cyan{border-color:rgba(6,182,212,0.3);background:rgba(6,182,212,0.04)}
   158|.ax-cyan .axis-id{color:#06b6d4;border-color:rgba(6,182,212,0.4)}
   159|.ax-pink{border-color:rgba(236,72,153,0.3);background:rgba(236,72,153,0.04)}
   160|.ax-pink .axis-id{color:#ec4899;border-color:rgba(236,72,153,0.4)}
   161|
   162|/* ── Timeline (story) ── */
   163|.timeline{margin-top:3rem;display:flex;flex-direction:column;gap:0;max-width:700px;margin-left:auto;margin-right:auto}
   164|.timeline-row{display:flex;gap:1.5rem;align-items:flex-start}
   165|.timeline-track{display:flex;flex-direction:column;align-items:center;flex-shrink:0}
   166|.timeline-node{width:44px;height:44px;border-radius:50%;display:flex;align-items:center;justify-content:center;font-size:.8rem;font-weight:800;color:#fff}
   167|.timeline-line{width:2px;height:40px;background:rgba(255,255,255,0.08);margin:4px 0}
   168|.timeline-card{flex:1;background:linear-gradient(145deg,var(--surface),var(--surface2));border:1px solid var(--border);border-radius:var(--radius);padding:1.5rem;margin-bottom:1rem}
   169|.timeline-card.card-highlight{border-color:rgba(236,72,153,0.25);background:linear-gradient(145deg,rgba(236,72,153,0.04),var(--surface2))}
   170|.timeline-label{font-size:.7rem;font-weight:700;letter-spacing:.1em;text-transform:uppercase;margin-bottom:.5rem}
   171|.timeline-text{font-size:.9rem;color:var(--text-dim);line-height:1.8}
   172|.timeline-text strong{color:var(--accent2)}
   173|.timeline-closing{font-size:.88rem;font-weight:600;margin-top:1rem;line-height:1.6}
   174|
   175|/* ── Install section ── */
   176|.install{text-align:center}
   177|.code-block{background:var(--surface);border:1px solid var(--border);border-radius:var(--radius);padding:1.2rem 1.5rem;margin:1rem auto;max-width:540px;font-family:'JetBrains Mono','Fira Code',monospace;font-size:.85rem;text-align:left;position:relative;cursor:pointer;transition:all .3s}
   178|.code-block:hover{border-color:var(--accent)}
   179|.code-block .prompt{color:var(--green)}
   180|.code-block .cmd{color:var(--text)}
   181|.code-block .comment{color:var(--text-dim)}
   182|.copy-btn{position:absolute;top:.8rem;right:.8rem;background:var(--surface2);border:1px solid var(--border);border-radius:8px;padding:.35rem .65rem;font-size:.7rem;color:var(--text-dim);cursor:pointer;transition:all .2s;font-family:inherit}
   183|.copy-btn:hover{color:var(--accent2);border-color:var(--accent)}
   184|.copy-btn.copied{color:var(--green);border-color:var(--green)}
   185|.code-label{font-size:.7rem;color:var(--text-dim);text-transform:uppercase;letter-spacing:.08em;margin-bottom:.5rem;font-family:'Inter',sans-serif}
   186|
   187|/* ── Footer ── */
   188|footer{padding:3rem 0;border-top:1px solid var(--border);text-align:center}
   189|footer p{margin:0 auto;font-size:.82rem;color:var(--text-dim)}
   190|footer .links{display:flex;gap:2rem;justify-content:center;margin-bottom:1rem}
   191|
   192|/* ── Scroll reveal ── */
   193|.reveal{opacity:0;transform:translateY(30px);transition:all .7s ease}
   194|.reveal.visible{opacity:1;transform:translateY(0)}
   195|
   196|/* ── Responsive ── */
   197|@media(max-width:768px){
   198|  .agent-grid{grid-template-columns:1fr}
   199|  .axes-grid{grid-template-columns:repeat(3,1fr)}
   200|  section{padding:4rem 0}
   201|  .lang-toggle{top:.8rem;right:.8rem}
   202|  .proof-box{flex-direction:column;text-align:center;padding:1rem}
   203|  .metrics-row{gap:1rem}
   204|  .metric-card{min-width:140px;padding:1.2rem 1rem}
   205|  
   206|  .pipeline-track::before{left:20px}
   207|  .pipe-step{gap:1rem}
   208|  .pipe-dot{width:40px;min-width:40px;height:40px;font-size:1.1rem}
   209|  
   210|  .timeline-row{gap:1rem}
   211|  .timeline-card{padding:1.2rem}
   212|}
   213|@media(max-width:480px){
   214|  .container{padding:0 1.2rem}
   215|  section{padding:3rem 0}
   216|  .axes-grid{grid-template-columns:repeat(2,1fr)}
   217|  .problem-grid{grid-template-columns:1fr}
   218|  
   219|  .metrics-row{display:grid;grid-template-columns:repeat(2,1fr);gap:.8rem;width:100%}
   220|  .metric-card{min-width:0;padding:1.2rem .8rem}
